  "yaku.chiihou.desc": { es: "Un no-oya gana con su primer robo, sin llamadas previas.", en: "A non-dealer wins on the first draw, before any call.", ja: "子が鳴きのない第一ツモで和了する。" },
  "yaku.pinfu.desc": { es: "Cuatro corridas y pareja sin valor, ganando con espera de dos lados.", en: "Four runs and a valueless pair, won on a two-sided wait.", ja: "順子4組と役牌以外の雀頭、両面待ちで和了する。" },
  "yaku.tanyao.desc": { es: "Solo fichas del 2 al 8: sin terminales ni honores.", en: "Only tiles 2 through 8: no terminals or honors.", ja: "一九字牌を使わずに揃える。" },
  "yaku.iipeiko.desc": { es: "Dos corridas idénticas; solo con mano cerrada.", en: "Two identical runs; closed hand only.", ja: "同じ順子を2組作る。門前のみ。" },
  "yaku.ryanpeiko.desc": { es: "Dos pares de corridas idénticas; solo con mano cerrada.", en: "Two pairs of identical runs; closed hand only.", ja: "一盃口を二つ作る。門前のみ。" },
