  "yaku.yakuhai-seat.desc": { es: "Trío o kan de tu viento de asiento.", en: "A triplet or kan of your seat wind.", ja: "自風牌の刻子か槓子を作る。" },
  "yaku.yakuhai-round.desc": { es: "Trío o kan del viento de la ronda.", en: "A triplet or kan of the round wind.", ja: "場風牌の刻子か槓子を作る。" },
