  "yaku.shousangen.desc": { es: "Tríos de dos dragones y pareja del tercero.", en: "Triplets of two dragons and a pair of the third.", ja: "三元牌の刻子2組と雀頭を作る。" },
  "yaku.honitsu.desc": { es: "Un solo palo más honores.", en: "One suit plus honor tiles.", ja: "一色の数牌と字牌だけで揃える。" },
