  "yaku.chiitoi.desc": { es: "Siete pares distintos; solo con mano cerrada.", en: "Seven distinct pairs; closed hand only.", ja: "七種の対子で揃える。門前のみ。" },
  "yaku.kokushi.desc": { es: "Una de cada terminal y honor, más una repetida.", en: "One of each terminal and honor, plus one duplicate.", ja: "一九字牌13種を全て集めて和了する。" },
